const LOGO_CASTELL_FAVICON = "data:image/png;base64,";
const LOGO_CASTELL_FULL = "data:image/png;base64,";

(function() {
  const link = document.createElement('link');
  link.rel = 'icon';
  link.type = 'image/png';
  link.href = LOGO_CASTELL_FAVICON;
  document.head.appendChild(link);
})();
